namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    // Get shapes
    const gert::Shape *x_shape = context->GetInputShape(0);   // x_t: (B, I)
    const gert::Shape *h_shape = context->GetInputShape(1);   // h:   (B, H)
    const gert::Shape *w_shape = context->GetInputShape(2);   // w_i2h: (H, K)
    const gert::Shape *wo_shape = context->GetInputShape(4);  // w_h2o: (O, H)

    uint32_t B = x_shape->GetDim(0);
    uint32_t I = x_shape->GetDim(1);
    uint32_t H = h_shape->GetDim(1);
    uint32_t O = wo_shape->GetDim(0);
    uint32_t K = I + H;

    VanillaRnnHiddenCustomTilingData tiling;
    tiling.set_B(B);
    tiling.set_I(I);
    tiling.set_H(H);
    tiling.set_O(O);
    tiling.set_K(K);
    tiling.set_blockDim(1);  // single core for simplicity

    // Prepare TCubeTiling for matmul1: (B, K) * (K, H) -> (B, H)
    AscendC::MatmulTiling tiling1;
    AscendC::MatmulTiling tiling2;
    AscendC::MatmulTiling::SetTiling(tiling1, B, K, H, AscendC::TPosition::GM, AscendC::CubeFormat::ND,
                                      AscendC::TPosition::GM, AscendC::CubeFormat::ND, true,
                                      AscendC::TPosition::GM, AscendC::CubeFormat::ND, false);
    AscendC::MatmulTiling::SetTiling(tiling2, B, H, O, AscendC::TPosition::GM, AscendC::CubeFormat::ND,
                                      AscendC::TPosition::GM, AscendC::CubeFormat::ND, true,
                                      AscendC::TPosition::GM, AscendC::CubeFormat::ND, false);

    // Copy TCubeTiling data into tiling fields (as raw uint32_t arrays)
    memcpy(tiling.get_tiling1(), &tiling1, sizeof(tiling1));
    memcpy(tiling.get_tiling2(), &tiling2, sizeof(tiling2));

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());
    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

