{
    const gert::Shape *h_shape = context->GetInputShape(1);   // h_in shape
    const gert::Shape *x_shape = context->GetInputShape(0);
    uint32_t B = x_shape->GetDim(0);
    uint32_t H = h_shape->GetDim(1);
    const gert::Shape *wo_shape = context->GetInputShape(4);
    uint32_t O = wo_shape->GetDim(0);

