using C_TYPE = AscendC::MatmulType<TPosition::GM, CubeFormat::ND, float, false, LayoutMode::NORMAL>;
using BIAS_TYPE = AscendC::MatmulType<TPosition::GM, CubeFormat::ND, float>;

