        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, B_ * I_ * sizeof(float));
        pipe_.InitBuffer(inQueueH_, BUFFER_NUM, B_ * H_ * sizeof(float));
        pipe_.InitBuffer(outQueueC_, BUFFER_NUM, B_ * H_ * sizeof(float)); // for pre after matmul1+bias
        pipe_.InitBuffer(outQueueH_, BUFFER_NUM, B_ * H_ * sizeof(float)); // tanh output (h_new)
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, B_ * O_ * sizeof(float)); // final output

        // Register matmul objects with the pipe and their tilings
        REGIST_MATMUL_OBJ(&pipe_, GetSysWorkSpacePtr(), matmul1_, &tiling1_);
        REGIST_MATMUL_OBJ(&pipe_, GetSysWorkSpacePtr(), matmul2_, &tiling2_);
    }

    __aicore__ inline void Process()
    {
        // Step 1: Copy x_t and h_in to local for concatenation (we'll do this manually)
        LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
